import type { NordicWebkitScope } from '../../../common/types';

const VERSION_REGEX = /^v\d+$/;

/**
 * Parse webkit engine version.
 *
 * Valid versions are:
 * - v<number> (e.g., 'v2')
 * - 'legacy'.
 *
 * When engine received is not valid, 'v1' is returned.
 */
export function parseEngineVersion(value: string) {
  return value && VERSION_REGEX.test(value) ? value : 'v1';
}

const SCOPE_DICTIONARY: Record<string, NordicWebkitScope> = {
  '0': 'view',
  '1': 'component',
  '2': 'page',
  '3': 'bottomsheet',
};

export function parseScopeValue(value: string) {
  return SCOPE_DICTIONARY[value];
}
